## 📡 API 接口设计

### REST API 规范

```typescript
// 基础路径
const BASE_URL = 'http://localhost:3000/api'

// 接口规范
interface ApiResponse<T> {
  success: boolean
  data: T
  message?: string
  timestamp: number
}

// 1. 概览数据 API
interface OverviewAPI {
  // 获取系统概览
  getOverview(): Promise<ApiResponse<OverviewData>>

  // 刷新概览数据
  refreshOverview(): Promise<ApiResponse<OverviewData>>
}

interface OverviewData {
  totalIterations: number
  successRate: number
  averageDuration: number
  activeAgents: number
  systemMetrics: {
    cpuUsage: number
    memoryUsage: number
    diskUsage: number
    uptime: number
  }
}

// 2. 迭代相关 API
interface IterationAPI {
  // 获取迭代列表（分页）
  getIterations(params: {
    page: number
    limit: number
    status?: 'running' | 'completed' | 'failed'
    search?: string
  }): Promise<ApiResponse<PaginatedResponse<Iteration>>>

  // 获取迭代详情
  getIteration(id: string): Promise<ApiResponse<IterationDetail>>

  // 回滚到指定迭代
  rollbackIteration(id: string): Promise<ApiResponse<RollbackResult>>

  // 获取当前运行迭代
  getCurrentIteration(): Promise<ApiResponse<Iteration | null>>

  // 对比两个迭代
  diffIterations(id1: string, id2: string): Promise<ApiResponse<IterationDiff>>
}

interface Iteration {
  id: string
  iterationNumber: number
  requirement: string
  status: 'running' | 'completed' | 'failed'
  progress: number
  duration: number
  createdAt: string
  completedAt?: string
  commitHash?: string
  branch?: string
}

// 3. Agent 相关 API
interface AgentAPI {
  // 获取所有 Agent 状态
  getAgents(): Promise<ApiResponse<AgentState[]>>

  // 获取特定 Agent 状态
  getAgent(name: string): Promise<ApiResponse<AgentState>>

  // 获取 Agent 性能统计
  getAgentStats(name: string): Promise<ApiResponse<AgentStats>>

  // 获取 Agent 执行历史
  getAgentHistory(name: string, params: {
    limit: number
  }): Promise<ApiResponse<AgentExecution[]>>
}

interface AgentState {
  name: string
  type: AgentType
  status: 'idle' | 'running' | 'completed' | 'failed'
  currentTask?: string
  progress: number
  executionTime: number
}

// 4. 系统相关 API
interface SystemAPI {
  // 获取系统指标
  getMetrics(): Promise<ApiResponse<SystemMetrics>>

  // 健康检查
  healthCheck(): Promise<ApiResponse<HealthStatus>>

  // 获取系统日志
  getLogs(params: {
    level?: 'error' | 'warn' | 'info' | 'debug'
    limit: number
    offset?: number
  }): Promise<ApiResponse<LogEntry[]>>
}

// 5. 项目相关 API
interface ProjectAPI {
  // 获取项目列表
  getProjects(): Promise<ApiResponse<Project[]>>

  // 获取项目详情
  getProject(id: string): Promise<ApiResponse<Project>>

  // 更新项目配置
  updateProject(id: string, config: ProjectConfig): Promise<ApiResponse<Project>>
}
```

### WebSocket 事件规范

```typescript
// WebSocket 连接
const WS_URL = 'ws://localhost:3000/api/ws'

// 事件类型定义
interface WebSocketEvents {
  // 连接事件
  'connected': ConnectionEvent

  // Agent 状态变化
  'agent.status_changed': AgentStatusEvent

  // 迭代状态变化
  'iteration.status_changed': IterationStatusEvent

  // 迭代进度更新
  'iteration.progress': IterationProgressEvent

  // 系统指标更新
  'system.metrics': SystemMetricsEvent

  // 日志条目
  'log.entry': LogEntryEvent

  // 错误通知
  'error': ErrorEvent

  // 心跳响应
  'pong': PongEvent
}

// 事件数据结构
interface AgentStatusEvent {
  agentName: string
  status: 'idle' | 'running' | 'completed' | 'failed'
  currentTask?: string
  progress: number
  timestamp: string
}

interface IterationProgressEvent {
  iterationId: string
  phase: string
  progress: number
  message: string
  timestamp: string
}

interface SystemMetricsEvent {
  cpuUsage: number
  memoryUsage: number
  activeConnections: number
  timestamp: string
}

interface LogEntryEvent {
  level: 'error' | 'warn' | 'info' | 'debug'
  agent?: string
  message: string
  timestamp: string
}
