## 🗄️ 数据库设计

### SQLite 表结构

```sql
-- 迭代记录表
CREATE TABLE iterations (
  id TEXT PRIMARY KEY,
  iteration_number INTEGER NOT NULL UNIQUE,
  requirement TEXT NOT NULL,
  status TEXT NOT NULL, -- 'running' | 'completed' | 'failed'
  progress INTEGER DEFAULT 0,
  requirement_analysis TEXT, -- PM 分析结果
  commit_hash TEXT,
  branch TEXT,
  files_changed INTEGER DEFAULT 0,
  lines_added INTEGER DEFAULT 0,
  lines_deleted INTEGER DEFAULT 0,
  duration INTEGER DEFAULT 0, -- 毫秒
  error_message TEXT,
  created_at INTEGER NOT NULL,
  completed_at INTEGER
);

CREATE INDEX idx_iterations_status ON iterations(status);
CREATE INDEX idx_iterations_created_at ON iterations(created_at DESC);

-- Agent 执行记录表
CREATE TABLE agent_executions (
  id TEXT PRIMARY KEY,
  iteration_id TEXT NOT NULL,
  agent_name TEXT NOT NULL,
  agent_type TEXT NOT NULL,
  status TEXT NOT NULL, -- 'idle' | 'running' | 'completed' | 'failed'
  task_description TEXT,
  result TEXT, -- JSON 格式的结果
  error_message TEXT,
  duration INTEGER DEFAULT 0,
  tokens_used INTEGER DEFAULT 0,
  created_at INTEGER NOT NULL,
  completed_at INTEGER,
  FOREIGN KEY (iteration_id) REFERENCES iterations(id)
);

CREATE INDEX idx_agent_executions_iteration ON agent_executions(iteration_id);
CREATE INDEX idx_agent_executions_agent ON agent_executions(agent_name);

-- 系统日志表
CREATE TABLE system_logs (
  id TEXT PRIMARY KEY,
  level TEXT NOT NULL, -- 'error' | 'warn' | 'info' | 'debug'
  agent_name TEXT,
  iteration_id TEXT,
  message TEXT NOT NULL,
  metadata TEXT, -- JSON 格式的额外数据
  created_at INTEGER NOT NULL
);

CREATE INDEX idx_logs_level ON system_logs(level);
CREATE INDEX idx_logs_created_at ON system_logs(created_at DESC);
CREATE INDEX idx_logs_iteration ON system_logs(iteration_id);

-- 系统指标快照表（用于图表）
CREATE TABLE system_metrics (
  id TEXT PRIMARY KEY,
  cpu_usage REAL NOT NULL,
  memory_usage REAL NOT NULL,
  active_connections INTEGER NOT NULL,
  timestamp INTEGER NOT NULL
);

CREATE INDEX idx_metrics_timestamp ON system_metrics(timestamp DESC);
```

