### 2.3 SystemResourceChart 实时更新方案

#### WebSocket 集成设计
```typescript
// src/components/charts/SystemResourceChart.vue

import { ref, onMounted, onUnmounted, computed } from 'vue'
import { useWebSocketStore } from '@/stores/websocket'
import { formatTime } from '@/utils/date'

const wsStore = useWebSocketStore()

// 图表数据
const chartData = ref({
  timestamps: [] as string[],
  cpu: [] as number[],
  memory: [] as number[]
})

// 配置参数
const props = defineProps<{
  refreshInterval?: number    // 刷新间隔（ms），默认 3000
  maxDataPoints?: number      // 最大数据点数，默认 100
  height?: string             // 图表高度，默认 '400px'
  showCpu?: boolean           // 显示 CPU，默认 true
  showMemory?: boolean        // 显示内存，默认 true
}>()

// 处理实时数据更新
const handleMetricsUpdate = (data: SystemMetrics) => {
  const timestamp = formatTime(new Date(), 'HH:mm:ss')

  // 添加新数据点
  chartData.value.timestamps.push(timestamp)
  chartData.value.cpu.push(data.cpuUsage)
  chartData.value.memory.push(data.memoryUsage)

  // 限制数据点数量
  const maxPoints = props.maxDataPoints || 100
  if (chartData.value.timestamps.length > maxPoints) {
    chartData.value.timestamps.shift()
    chartData.value.cpu.shift()
    chartData.value.memory.shift()
  }

  // 更新图表
  updateChart()
}

// 订阅 WebSocket 事件
onMounted(() => {
  // 订阅系统指标事件
  wsStore.on('system.metrics', handleMetricsUpdate)

  // 定时请求系统指标
  const interval = setInterval(() => {
    wsStore.send({ type: 'subscribe', channel: 'system.metrics' })
  }, props.refreshInterval || 3000)

  // 清理函数
  onUnmounted(() => {
    wsStore.off('system.metrics', handleMetricsUpdate)
    clearInterval(interval)
  })
})
```

