```vue
<template>
  <div class="iteration-progress-section">
    <div class="progress-header">
      <span class="progress-label">执行进度</span>
      <span class="progress-percentage">{{ iteration.progress }}%</span>
    </div>

    <el-progress
      :percentage="iteration.progress"
      :status="progressStatus"
      :stroke-width="12"
      :show-text="false"
      :duration="500"
      :color="progressColor"
    />

    <div v-if="remainingTime" class="progress-footer">
      <el-icon><Timer /></el-icon>
      <span>预计剩余: {{ remainingTime }}</span>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue'
import { calculateRemainingTime, formatRemainingTime } from '@/utils/date'

const progressStatus = computed(() => {
  const status = iteration.value?.status
  if (status === 'completed') return 'success'
  if (status === 'failed') return 'exception'
  return undefined
})

const progressColor = computed(() => {
  const progress = iteration.value?.progress || 0
  if (progress < 30) return '#f56c6c'
  if (progress < 70) return '#e6a23c'
  return '#67c23a'
})

const remainingTime = computed(() => {
  if (!iteration.value?.startTime || iteration.value.progress >= 100) {
    return null
  }

  const seconds = calculateRemainingTime(
    new Date(iteration.value.startTime),
    iteration.value.progress
  )

  return formatRemainingTime(seconds)
})
</script>
```

