### 4.2 集成测试策略

#### WebSocket 集成测试
```typescript
// tests/integration/websocket-chart-integration.test.ts

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { mount } from '@vue/test-utils'
import { createPinia } from 'pinia'
import SystemResourceChart from '@/components/charts/SystemResourceChart.vue'
import { useWebSocketStore } from '@/stores/websocket'

describe('WebSocket 图表集成', () => {
  let wsStore: any
  let mockWs: any

  beforeEach(() => {
    const pinia = createPinia()
    wsStore = useWebSocketStore()

    // Mock WebSocket
    mockWs = {
      send: vi.fn(),
      close: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn()
    }

    vi.stubGlobal('WebSocket', vi.fn(() => mockWs))
  })

  afterEach(() => {
    vi.unstubAllGlobals()
  })

  it('应该订阅 system.metrics 事件', () => {
    const wrapper = mount(SystemResourceChart, {
      global: {
        plugins: [createPinia()]
      }
    })

    expect(wsStore.on).toHaveBeenCalledWith(
      'system.metrics',
      expect.any(Function)
    )
  })

  it('应该在收到数据时更新图表', async () => {
    const wrapper = mount(SystemResourceChart, {
      global: {
        plugins: [createPinia()]
      }
    })

    const mockData = {
      timestamp: new Date().toISOString(),
      cpuUsage: 45.5,
      memoryUsage: 68.2
    }

    // 模拟收到 WebSocket 数据
    wsStore.emit('system.metrics', mockData)

    await wrapper.vm.$nextTick()

    // 验证图表数据已更新
    expect(wrapper.vm.chartData.cpu).toContain(45.5)
    expect(wrapper.vm.chartData.memory).toContain(68.2)
  })

  it('应该限制数据点数量', async () => {
    const wrapper = mount(SystemResourceChart, {
      props: {
        maxDataPoints: 10
      },
      global: {
        plugins: [createPinia()]
      }
    })

    // 模拟收到 15 个数据点
    for (let i = 0; i < 15; i++) {
      wsStore.emit('system.metrics', {
        timestamp: new Date().toISOString(),
        cpuUsage: 50,
        memoryUsage: 60
      })
    }

    await wrapper.vm.$nextTick()

    // 验证只保留最后 10 个数据点
    expect(wrapper.vm.chartData.timestamps.length).toBe(10)
  })
})
```

