## 📋 详细开发任务清单

### 阶段 1: AutoIterationEngine 集成（Day 1-2, 2天）

#### 任务 1.1: 集成 Dashboard 服务到 AutoIterationEngine

**优先级**: 🔴 P0（最高）  
**预计时间**: 4小时  
**负责人**: 后端开发

**实施步骤**:

```typescript
// 文件: src/auto-iteration.ts

// 1. 导入 Dashboard 服务
import { getServices } from './dashboard/server';

// 2. 在 AutoIterationEngine 类中添加服务引用
export class AutoIterationEngine {
  private iterationService: IterationService;
  private realtimeService: RealtimeService;
  private agentService: AgentService;

  async initialize() {
    // 获取 Dashboard 服务实例
    const services = getServices();
    this.iterationService = services.iterationService;
    this.realtimeService = services.realtimeService;
    this.agentService = services.agentService;
  }

  // 3. 在迭代开始时创建记录
  async startIteration(requirement: string) {
    const iteration = this.iterationService.create({
      iterationNumber: this.count,
      status: IterationStatus.RUNNING,
      requirement,
      startedAt: new Date()
    });

    // 广播迭代开始
    this.realtimeService.broadcastIterationStatusChange({
      iterationId: iteration.id,
      iterationNumber: iteration.iterationNumber,
      status: IterationStatus.RUNNING,
      timestamp: new Date()
    });

    return iteration;
  }

  // 4. 在每个 Agent 执行时更新进度
  async executeAgent(agentName: string, task: string) {
    // 更新 Agent 状态
    this.agentService.updateProgress(
      currentIteration.id,
      agentName,
      0,
      task
    );

    // 广播 Agent 状态变化
    this.realtimeService.broadcastAgentStatusChange({
      iterationId: currentIteration.id,
      agentName,
      agentType: agentName,
      status: 'running',
      progress: 0,
      timestamp: new Date()
    });

    try {
      // 执行 Agent 逻辑
      const result = await this.runAgent(agentName, task);

      // 更新完成状态
      this.agentService.updateProgress(
        currentIteration.id,
        agentName,
        100,
        `${task} - 完成`
      );

      return result;
    } catch (error) {
      // 更新错误状态
      this.agentService.updateProgress(
        currentIteration.id,
        agentName,
        -1,
        `${task} - 失败: ${error.message}`
      );

      throw error;
    }
  }

  // 5. 在迭代完成时更新状态
  async completeIteration(success: boolean, gitCommit?: any) {
    const status = success 
      ? IterationStatus.COMPLETED 
      : IterationStatus.FAILED;

    this.iterationService.update(currentIteration.id, {
      status,
      completedAt: new Date(),
      gitCommit
    });

    // 广播完成事件
    this.realtimeService.broadcastIterationStatusChange({
      iterationId: currentIteration.id,
      iterationNumber: currentIteration.iterationNumber,
      status,
      timestamp: new Date()
    });
  }
}
```

