#### 任务 2.1: 完善 WebSocket 事件处理

**优先级**: 🟡 P1  
**预计时间**: 4小时  
**负责人**: 前端开发

**实施步骤**:

```typescript
// 文件: dashboard/src/stores/websocket.ts

import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { WebSocketManager } from '@/utils/websocket-manager';
import { useAgentStore } from './agent';
import { useIterationStore } from './iteration';
import { useOverviewStore } from './overview';

export const useWebSocketStore = defineStore('websocket', () => {
  const wsManager = new WebSocketManager();
  const connected = ref(false);
  const connecting = ref(false);

  const agentStore = useAgentStore();
  const iterationStore = useIterationStore();
  const overviewStore = useOverviewStore();

  async function connect() {
    if (connected.value || connecting.value) return;

    connecting.value = true;

    try {
      await wsManager.connect(import.meta.env.VITE_WS_URL);

      // 注册事件处理器
      wsManager.on('connected', () => {
        connected.value = true;
        connecting.value = false;
      });

      wsManager.on('disconnected', () => {
        connected.value = false;
        // 自动重连
        setTimeout(() => connect(), 3000);
      });

      // 迭代状态变化
      wsManager.on('iteration.status_changed', (data) => {
        iterationStore.updateIterationStatus(data);
        overviewStore.refreshOverview();
      });

      // Agent 状态变化
      wsManager.on('agent.status_changed', (data) => {
        agentStore.updateAgentStatus(data);
      });

      // 迭代进度更新
      wsManager.on('iteration.progress', (data) => {
        iterationStore.updateProgress(data);
      });

      // 系统指标
      wsManager.on('system.metrics', (data) => {
        overviewStore.updateMetrics(data);
      });

      // 日志推送
      wsManager.on('log', (data) => {
        // 存储到日志 store
        console.log('[Log]', data);
      });

    } catch (error) {
      connecting.value = false;
      console.error('WebSocket 连接失败:', error);
    }
  }

  function disconnect() {
    wsManager.disconnect();
    connected.value = false;
  }

  return {
    connected,
    connecting,
    connect,
    disconnect
  };
});
```

