**Task 3.2: WebSocket 完整集成** (4h)

**集成任务**:
1. WebSocket Store 完善
2. 自动重连机制
3. 心跳检测
4. 错误处理
5. 事件订阅管理

**完整实现**:
```typescript
// stores/websocket.ts
import { defineStore } from 'pinia'

export const useWebSocketStore = defineStore('websocket', {
  state: () => ({
    ws: null as WebSocket | null,
    connected: false,
    reconnectAttempts: 0,
    maxReconnectAttempts: 5,
    reconnectInterval: 2000,
    heartbeatInterval: 30000,
    heartbeatTimer: null as NodeJS.Timeout | null,
    subscriptions: new Map<string, Set<Function>>(),
    messageQueue: [] as any[]
  }),

  actions: {
    connect(url: string = 'ws://localhost:3000/api/ws') {
      if (this.ws?.readyState === WebSocket.OPEN) {
        console.log('WebSocket already connected')
        return
      }

      try {
        this.ws = new WebSocket(url)

        this.ws.onopen = () => {
          console.log('✅ WebSocket connected')
          this.connected = true
          this.reconnectAttempts = 0

          // 发送排队的消息
          this.flushMessageQueue()

          // 启动心跳
          this.startHeartbeat()

          // 触发连接成功事件
          this.publish('connection.status', { connected: true })
        }

        this.ws.onmessage = (event) => {
          try {
            const { event: type, data } = JSON.parse(event.data)

            // 处理心跳响应
            if (type === 'pong') {
              return
            }

            // 分发事件到订阅者
            this.publish(type, data)

            // 特殊事件处理
            this.handleSpecialEvent(type, data)
          } catch (error) {
            console.error('Failed to parse WebSocket message:', error)
          }
        }

        this.ws.onerror = (error) => {
          console.error('WebSocket error:', error)
          this.publish('connection.error', { error })
        }

        this.ws.onclose = (event) => {
          console.log('WebSocket closed:', event.code, event.reason)
          this.connected = false
          this.stopHeartbeat()

          // 触发断开连接事件
          this.publish('connection.status', { connected: false })

          // 尝试重连
          this.reconnect()
        }
      } catch (error) {
        console.error('Failed to create WebSocket:', error)
        this.reconnect()
      }
    },

    disconnect() {
      this.stopHeartbeat()
      if (this.ws) {
        this.ws.close()
        this.ws = null
      }
      this.connected = false
    },

    reconnect() {
      if (this.reconnectAttempts >= this.maxReconnectAttempts) {
        console.error('Max reconnect attempts reached')
        this.publish('connection.failed', { 
          attempts: this.reconnectAttempts 
        })
        return
      }

      this.reconnectAttempts++
      const delay = this.reconnectInterval * this.reconnectAttempts

      console.log(`Reconnecting in ${delay}ms (attempt ${this.reconnectAttempts})`)

      setTimeout(() => {
        this.connect()
      }, delay)
    },

    startHeartbeat() {
      this.stopHeartbeat()
      this.heartbeatTimer = setInterval(() => {
        if (this.ws?.readyState === WebSocket.OPEN) {
          this.send({ type: 'ping' })
        }
      }, this.heartbeatInterval)
    },

    stopHeartbeat() {
      if (this.heartbeatTimer) {
        clearInterval(this.heartbeatTimer)
        this.heartbeatTimer = null
      }
    },

    send(data: any) {
      if (this.ws?.readyState === WebSocket.OPEN) {
        this.ws.send(JSON.stringify(data))
      } else {
        // 连接未建立,加入队列
        this.messageQueue.push(data)
      }
    },

    flushMessageQueue() {
      while (this.messageQueue.length > 0) {
        const message = this.messageQueue.shift()
        this.send(message)
      }
    },

    subscribe(event: string, callback: Function) {
      if (!this.subscriptions.has(event)) {
        this.subscriptions.set(event, new Set())
      }
      this.subscriptions.get(event)!.add(callback)

      // 返回取消订阅函数
      return () => {
        this.unsubscribe(event, callback)
      }
    },

    unsubscribe(event: string, callback: Function) {
      const callbacks = this.subscriptions.get(event)
      if (callbacks) {
        callbacks.delete(callback)
      }
    },

    publish(event: string, data: any) {
      const callbacks = this.subscriptions.get(event)
      if (callbacks) {
        callbacks.forEach(callback => callback(data))
      }
    },

    handleSpecialEvent(type: string, data: any) {
      // 处理需要特殊处理的事件
      switch (type) {
        case 'iteration.started':
        case 'iteration.progress':
        case 'iteration.completed':
        case 'iteration.failed':
          // 这些事件会触发 iteration store 更新
          const iterationStore = useIterationStore()
          iterationStore.handleIterationEvent(type, data)
          break

        case 'agent.status_changed':
        case 'agent.progress':
          // 这些事件会触发 agent store 更新
          const agentStore = useAgentStore()
          agentStore.handleAgentEvent(type, data)
          break
      }
    }
  }
})
```

