**实现代码**:
```typescript
// auto-iteration.ts
import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private iterationService: IterationService
  private realtimeService: RealtimeService

  constructor() {
    const services = getServices()
    this.iterationService = services.iterationService
    this.realtimeService = services.realtimeService
  }

  async startIteration(requirement: string) {
    // 1. 创建迭代记录
    const iteration = await this.iterationService.create({
      iterationNumber: this.count,
      status: 'running',
      requirement,
      startedAt: new Date()
    })

    // 2. 通知前端迭代开始
    this.realtimeService.broadcast('iteration.started', iteration)

    try {
      // 3. 执行产品经理 Agent
      await this.runAgent('product-manager', requirement)

      // 4. 执行架构师 Agent
      await this.runAgent('architect', requirement)

      // ... 其他 Agents

      // 5. 迭代完成
      await this.iterationService.update(iteration.id, {
        status: 'completed',
        completedAt: new Date()
      })

      this.realtimeService.broadcast('iteration.completed', iteration)

    } catch (error) {
      // 迭代失败
      await this.iterationService.update(iteration.id, {
        status: 'failed',
        error: error.message,
        completedAt: new Date()
      })

      this.realtimeService.broadcast('iteration.failed', {
        iteration,
        error: error.message
      })
    }
  }

  async runAgent(agentName: string, task: string) {
    // 推送 Agent 状态
    this.realtimeService.broadcast('agent.status_changed', {
      name: agentName,
      status: 'running',
      task
    })

    const startTime = Date.now()

    try {
      // 执行 Agent 逻辑
      const agent = this.agents[agentName]
      const result = await agent.execute(task)

      const duration = Date.now() - startTime

      // 推送完成状态
      this.realtimeService.broadcast('agent.status_changed', {
        name: agentName,
        status: 'completed',
        result,
        duration
      })

    } catch (error) {
      // 推送错误状态
      this.realtimeService.broadcast('agent.status_changed', {
        name: agentName,
        status: 'failed',
        error: error.message
      })

      throw error
    }
  }
}
```

