    setActivePinia(createPinia())
    global.WebSocket = vi.fn().mockImplementation(() => ({
      send: vi.fn(),
      close: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn()
    })) as any
  })

  it('should connect to WebSocket', () => {
    const store = useWebSocketStore()
    store.connect('ws://localhost:3000/api/ws')
    expect(WebSocket).toHaveBeenCalledWith('ws://localhost:3000/api/ws')
  })

  it('should handle reconnection', async () => {
    const store = useWebSocketStore()
    store.connect('ws://localhost:3000/api/ws')

    // 模拟连接关闭
    const ws = (store.ws as any)
    ws.onclose({ code: 1000, reason: 'Normal closure' })

    expect(store.reconnectAttempts).toBe(1)
  })

  it('should subscribe and publish events', () => {
    const store = useWebSocketStore()
    const callback = vi.fn()

    store.subscribe('test.event', callback)
    store.publish('test.event', { data: 'test' })

    expect(callback).toHaveBeenCalledWith({ data: 'test' })
  })
})
```

